# patch_ctr_sections_batch2.ps1
# Adds EVOLUTION, ESSENTIAL, Transferable Wisdom, Surprising Truth, *Hint: to CTR-021 to CTR-042
param([string]$BASE = "C:\ASK\MyWorkspace\sk-keys\dictionary\tier-6-infrastructure-devops\CTR-containers")

$utf8 = New-Object System.Text.UTF8Encoding $false

function Read-File($path) {
    $bytes = [System.IO.File]::ReadAllBytes($path)
    $start = if ($bytes[0] -eq 0xEF -and $bytes[1] -eq 0xBB -and $bytes[2] -eq 0xBF) { 3 } else { 0 }
    $txt = [System.Text.Encoding]::UTF8.GetString($bytes, $start, $bytes.Length - $start)
    return $txt -replace "`r`n", "`n"
}

function Write-File($path, $content) {
    [System.IO.File]::WriteAllText($path, $content, $utf8)
}

function Patch-File($code, $evolution, $essential, $accidental, $wisdom, $wisdomApps, $truth, $hint1, $hint2, $hint3) {
    $f = Get-ChildItem $BASE -Filter "$code*.md" | Select-Object -First 1
    if (-not $f) { Write-Host "NOT FOUND: $code"; return }
    $n = Read-File $f.FullName

    if ($n -notmatch '\*\*EVOLUTION:\*\*') {
        $evoText = "`n`n**EVOLUTION:** $evolution"
        $n = [regex]::Replace($n, '(?s)(\*\*THE INVENTION MOMENT:\*\*.+?)(\n\n---)', { $args[0].Groups[1].Value + $evoText + $args[0].Groups[2].Value })
    }

    if ($n -notmatch 'ESSENTIAL vs ACCIDENTAL') {
        $essText = "`n`n**ESSENTIAL vs ACCIDENTAL COMPLEXITY:**`n**Essential:** $essential`n**Accidental:** $accidental"
        $n = [regex]::Replace($n, '(?s)(\*\*Cost:\*\*.+?)(\n\n---)', { $args[0].Groups[1].Value + $essText + $args[0].Groups[2].Value })
    }

    if ($n -notmatch 'Transferable Wisdom') {
        $wisdomSection = @"

---

### 💎 Transferable Wisdom

**Reusable Engineering Principle:** $wisdom

**Where else this pattern appears:**
$wisdomApps

---

### 💡 The Surprising Truth

$truth

"@
        $n = $n -replace '(\n---\n\n### 📌 Quick Reference Card)', ($wisdomSection + '$1')
    }

    if ($n -notmatch '\*Hint:') {
        $n = [regex]::Replace($n, '(1\. \*\*\(Type [A-F][^)]*\).*?)(\n\n2\.)', { $args[0].Groups[1].Value + "`n`n   $hint1" + $args[0].Groups[2].Value })
        $n = [regex]::Replace($n, '(2\. \*\*\(Type [A-F][^)]*\).*?)(\n\n3\.)', { $args[0].Groups[1].Value + "`n`n   $hint2" + $args[0].Groups[2].Value })
        $n = [regex]::Replace($n, '(3\. \*\*\(Type [A-F][^)]*\).*?)(\s*$)', { $args[0].Groups[1].Value + "`n`n   $hint3`n" })
    }

    Write-File $f.FullName $n
    Write-Host "PATCHED: $($f.Name)"
}

# --- CTR-021: Container Security ---
Patch-File "CTR-021" `
    "Early container security (2013-2016) relied on Docker daemon flags (--cap-drop, --security-opt). The Center for Internet Security (CIS) Docker Benchmark (2016) formalised security hardening guidelines. Kubernetes PodSecurityPolicy (deprecated 2021) and Pod Security Standards/Admission (Kubernetes 1.25+) added cluster-level enforcement. seccomp profiles, AppArmor, and SELinux integration matured between 2018-2022. Supply-chain security (sigstore, SBOM, SLSA) became a compliance requirement from 2023." `
    "Running untrusted code in a shared kernel environment requires multiple layers of defence - namespace isolation, capability dropping, syscall filtering, and non-root execution are inherently necessary to reduce the kernel attack surface." `
    "The specific security tools (AppArmor vs SELinux, seccomp vs gVisor, OPA vs Kyverno) and their configuration formats are implementation choices; the underlying defence-in-depth principle is essential." `
    "Container security is defence-in-depth: no single control is sufficient. Layer namespace isolation plus capability reduction plus syscall filtering plus non-root execution plus image scanning - each layer reduces blast radius when another layer fails." `
    "- **Network security defence-in-depth** - firewall plus IDS plus encryption plus access control; no single layer prevents all attacks; each layer reduces what a breach exposes`n- **Application security OWASP controls** - input validation plus output encoding plus authentication plus authorisation; same layered philosophy applied to web app security`n- **Physical security** - perimeter fence plus guard plus badge access plus CCTV plus vault - no single control covers all attack vectors" `
    "The Linux capability model has 41 distinct capabilities. A container running as root with no --cap-drop still has ALL 41 capabilities including CAP_NET_ADMIN (reconfigure network interfaces), CAP_SYS_ADMIN (mount filesystems, change namespaces), and CAP_SYS_PTRACE (trace any process). A container running as root with --cap-drop ALL --cap-add NET_BIND_SERVICE has effectively one capability. The difference in attack surface between these two configurations is enormous - yet both show 'running as root' in a security scan. The UID is just the starting point of container security analysis." `
    "*Hint:* Research the capabilities of a default Docker container (docker run --cap-add=SYS_ADMIN) vs a hardened container (--cap-drop=all --no-new-privileges:true) and what specific attacks each enables or prevents." `
    "*Hint:* Investigate seccomp profiles: the Docker default seccomp profile blocks 44 syscalls. Look at which syscalls are blocked and understand why each one represents a security risk if accessible from a container." `
    "*Hint:* Look at Falco (CNCF runtime security tool) and how it uses eBPF to detect anomalous syscall patterns (e.g., a web server process suddenly forking a shell) as an indicator of container compromise."

# --- CTR-022: Distroless Images ---
Patch-File "CTR-022" `
    "Distroless images were pioneered by Google (gcr.io/distroless) starting around 2017. Chainguard extended the concept in 2022 with Wolfi-based distroless images offering daily CVE updates. The concept emerged from Google's internal container practices at scale. Alpine Linux (minimal base images) predated distroless but still includes a shell; distroless removes the shell entirely as a security measure." `
    "Runtime containers need only the application and its direct runtime dependencies - the OS package manager, shell, and debug tools are build-time requirements, not runtime requirements. This separation is an inherent architectural principle." `
    "The specific distroless image format (Google's gcr.io/distroless vs Chainguard vs Alpine-based minimal images) and the multi-stage build pattern used to achieve them are implementation choices." `
    "Ship only what you need to run - not what you need to build. Every extra package, binary, and library in a production image is an attack surface that must be maintained, scanned, and patched indefinitely." `
    "- **AWS Lambda layers** - separate the runtime layer from the function code; Lambda itself provides the minimum execution environment and only the function code plus declared layers are user-managed`n- **Serverless FaaS cold start optimisation** - minimise the ZIP/container size to reduce cold start latency; every MB of unnecessary code increases startup time`n- **Embedded firmware** - strip debug symbols, logging, and unused code paths from production firmware; every kilobyte is deliberate in constrained environments" `
    "Distroless images have no /bin/sh, no ls, no curl, no wget. This is celebrated as a security feature - an attacker who breaks into the container has no shell to execute commands. However, this also means you cannot exec into the container for debugging: docker exec -it mycontainer /bin/sh fails with no such file. Production debugging requires either sidecar debug containers (kubectl debug), ephemeral containers in Kubernetes, or logging and tracing instrumentation built into the app itself. Organisations that adopt distroless must invest in observability before removing their debugging escape hatch." `
    "*Hint:* Build the same Java application with FROM openjdk:17-jdk-slim and FROM gcr.io/distroless/java17 and compare: image size, docker history layer count, number of CVEs reported by trivy, and what docker exec can access." `
    "*Hint:* Research Kubernetes ephemeral debug containers (kubectl debug -it pod/mypod --image=ubuntu --target=mycontainer) and how they enable attaching a debug shell to a running distroless container without modifying the pod spec." `
    "*Hint:* Investigate Chainguard's Wolfi-based distroless images and how their daily rebuilds on upstream package releases differ from Google's gcr.io/distroless in terms of CVE patch latency."

# --- CTR-023: Image Scanning ---
Patch-File "CTR-023" `
    "Image scanning emerged as a practice around 2015 as container adoption in enterprises triggered security audit requirements. Clair (CoreOS/Red Hat, 2015) was the first widely-used open-source scanner. Trivy (Aqua Security, 2019) simplified scanning to a single CLI command. ECR native scanning (Snyk-powered) launched in 2020. SBOM generation (syft, 2021) formalised the dependency inventory. Sigstore and SLSA provenance attestations (2022+) added cryptographic supply-chain verification." `
    "Running software from third-party base images creates inherited risk - any CVE in an upstream package affects all images built from that base. Continuous vulnerability scanning is inherently required for any production software supply chain." `
    "The specific scanning tools (Trivy, Grype, Clair, Snyk), their CVE database sources (NVD, OSV, GitHub Advisory), and their output formats (JSON, SARIF, CycloneDX) are implementation choices." `
    "You cannot ship what you cannot see. A complete inventory of every component in a production artifact (SBOM) plus continuous comparison against known vulnerability databases is the minimum viable supply-chain security hygiene." `
    "- **npm audit** - scans JavaScript dependencies against npm's advisory database; the SBOM for Node.js is package-lock.json; npm audit fix is the automated remediation equivalent of rebuilding with updated base images`n- **OWASP Dependency Check** - Java/Maven dependency vulnerability scanning; pom.xml is the SBOM; CVSS score thresholds map to trivy severity filters`n- **Antivirus software** - scheduled signature-based scanning of files against known malware databases; the AV signature database is the CVE database equivalent" `
    "The most critical CVEs in container images are frequently not in the application code - they are in the base image OS packages. A Java Spring Boot service might have zero application-level vulnerabilities but inherit 50 CVEs from Ubuntu packages in the FROM ubuntu:20.04 base that the application never calls. Teams who focus security scanning only on their own code miss the largest attack surface in their containers. Base image selection and update frequency determine the floor of container security, not application code quality." `
    "*Hint:* Run trivy image nginx:1.25 and trivy image nginx:alpine for the same nginx version - compare the CVE counts and severities; understand why Alpine's minimal package set results in dramatically fewer findings." `
    "*Hint:* Research how Trivy's --ignore-unfixed flag changes the actionable findings count and the risk/trade-off of excluding vulnerabilities for which no fixed version exists yet." `
    "*Hint:* Investigate SLSA provenance attestations and how they extend scanning beyond CVEs to verify that a container image was built from a specific git commit by a specific CI system - closing the supply chain verification gap."

# --- CTR-024: OCI Standard ---
Patch-File "CTR-024" `
    "The OCI (Open Container Initiative) was founded in June 2015 by Docker, CoreOS, and other industry members under the Linux Foundation. OCI Image Spec 1.0 released 2017. OCI Distribution Spec 1.0 released 2021. OCI Runtime Spec 1.0 (runtime-spec) defines what a container runtime must implement. OCI Artifacts (2019+) extended the registry API to store arbitrary artifacts beyond container images, enabling Helm charts, SBOMs, and Wasm modules in OCI-compliant registries." `
    "Interoperability between container build tools, registries, and runtimes requires a common format specification - without a standard, every vendor's toolchain is siloed." `
    "The specific JSON manifest structure, layer TAR format, runtime config schema, and registry HTTP API paths are OCI implementation choices; the need for a common standard is essential." `
    "Open standards create the competitive moat for tool builders at the layer (best build tool, best registry, best runtime) and prevent vendor lock-in at the interface. Define the interface clearly; compete on implementation quality." `
    "- **TCP/IP** - the protocol standard that enables any OS to communicate with any network; without it, every vendor's network stack would be proprietary`n- **JDBC (Java Database Connectivity)** - the interface standard that lets Java applications switch databases (MySQL, PostgreSQL, Oracle) by changing only the driver JAR`n- **POSIX** - the Unix API standard that enables portable C programs; Linux, macOS, and BSD all implement POSIX, enabling software portability across OSes" `
    "The OCI Runtime Spec defines a container as a process with a bundle - a root filesystem and a config.json. The spec is deliberately minimal: it defines what inputs a runtime receives and what system state it must create, but it does not specify HOW the runtime achieves isolation. This means runc (using Linux namespaces), gVisor (using a user-space kernel), Kata Containers (using a lightweight VM), and Wasm runtimes (using WebAssembly sandboxing) are ALL OCI-compliant runtimes that can be plugged into Kubernetes via CRI - they just achieve isolation through completely different mechanisms." `
    "*Hint:* Read the OCI Runtime Spec's config.json specification and map each field to the corresponding Linux syscall it triggers (mounts, namespaces, capabilities, seccomp) to understand what a compliant runtime must implement." `
    "*Hint:* Research OCI Artifacts (oras.land) and how they use the same OCI registry API to store Helm charts, WASM modules, and Sigstore signatures - demonstrating the registry-as-general-artifact-store pattern." `
    "*Hint:* Compare what runc (OCI reference runtime), gVisor (runsc, user-space kernel), and Kata Containers (kata-runtime, microVM) each do with the same OCI bundle - how does each achieve different isolation guarantees from identical input?"

# --- CTR-025: containerd ---
Patch-File "CTR-025" `
    "containerd was extracted from Docker Engine in 2016 and donated to CNCF in 2017. Kubernetes CRI (Container Runtime Interface) v1 (2016) motivated its extraction. containerd 1.0 (2017) was the first stable release. Kubernetes deprecated dockershim in 1.20 (2020) and removed it in 1.24 (2022), making containerd (or CRI-O) the required runtime for all Kubernetes clusters. containerd 2.0 (2024) added sandbox API support for Kata and gVisor integration." `
    "A Kubernetes cluster needs a standard, embeddable container runtime that pulls images, creates containers, and manages their lifecycle - this operational need is inherent and independent of Docker's developer-facing tooling." `
    "The specific gRPC CRI API, containerd's plugin architecture (snapshotter, content store, runtime plugins), and the CTD (containerd CLI) tools are implementation choices; any OCI-compliant runtime implementing the CRI API is a valid Kubernetes runtime." `
    "Separate the low-level runtime (create/start/stop containers) from the higher-level orchestration (schedule/scale/heal). The runtime should be minimal, stable, and embeddable; the orchestrator should be pluggable." `
    "- **Java NIO vs application frameworks** - NIO is the low-level I/O primitive; Spring/Netty builds high-level abstractions on top; similarly, containerd is the primitive; Kubernetes is the orchestration layer on top`n- **SQLite vs application ORMs** - SQLite is the minimal embedded database; application frameworks provide higher-level query abstractions; containerd is the SQLite of container runtimes`n- **Linux kernel vs init systems** - the kernel provides process primitives; systemd provides lifecycle management on top; containerd provides container primitives; Kubernetes provides lifecycle management on top" `
    "The Kubernetes deprecation of dockershim in 2022 caused panic because engineers thought their docker build workflow was breaking. In reality, dockershim was ONLY the adapter that let the Kubernetes kubelet call Docker daemon instead of a proper CRI runtime. Docker images (OCI format) continued to work identically with containerd. The only affected component was the kubelet-to-runtime communication path on worker nodes - invisible to developers. The deprecation removed approximately 25,000 lines of maintenance burden from the Kubernetes codebase while changing zero developer workflows." `
    "*Hint:* On a Kubernetes node, use crictl (containerd's Kubernetes-aware CLI) instead of docker to inspect running containers: crictl ps, crictl logs, crictl inspect - observe that it shows the same containers as kubectl get pods." `
    "*Hint:* Research containerd's plugin architecture: the snapshotter plugin (overlayfs, devmapper, nydus), the content store, and the runtime plugin (runc, kata, gvisor) - understand how each is independently swappable." `
    "*Hint:* Investigate containerd's nerdctl CLI (a Docker-compatible CLI for containerd) and how it enables docker pull/run/build commands without a Docker daemon - what containerd features does nerdctl expose that docker CLI does not?"

# --- CTR-026: Container Orchestration ---
Patch-File "CTR-026" `
    "Container orchestration emerged as a problem around 2014-2015 when teams ran 10+ containers in production. Apache Mesos (2009, generalised resource scheduling), Kubernetes (June 2014, open-sourced by Google based on Borg), and Docker Swarm (2015) competed for the orchestration market. By 2017 Kubernetes had won. CNCF (Cloud Native Computing Foundation) acceptance in 2016 accelerated Kubernetes adoption. Managed Kubernetes services (EKS 2018, GKE 2014, AKS 2017) made production Kubernetes accessible without cluster management overhead." `
    "Managing containers across multiple hosts - scheduling, healing, scaling, networking, and configuration - cannot be done manually at scale. Orchestration is inherently necessary the moment containers exceed a single host." `
    "Kubernetes's specific YAML-based declarative primitives (Deployment, Service, ConfigMap, Secret), its controller reconciliation model, and its etcd-based state store are implementation choices; the orchestration function itself is essential." `
    "A control loop (observe desired state, observe actual state, take corrective action) is the fundamental pattern for managing any distributed system reliably. The system continuously self-corrects without human intervention." `
    "- **Thermostat (closed-loop control)** - observes current temperature, compares to desired temperature, activates heating/cooling to close the gap; Kubernetes controllers use identical observe-compare-act logic`n- **TCP congestion control** - continuously observes network conditions (packet loss, RTT), adjusts send window to approach but not exceed capacity`n- **GitOps (ArgoCD/Flux)** - observes git repo (desired state), compares to cluster state (actual state), syncs until they match - a container orchestration control loop over git" `
    "Kubernetes manages state through a reconciliation loop, not a transaction log. When you kubectl apply a Deployment, Kubernetes does NOT execute a sequential plan. Instead, the Deployment controller watches for Deployments whose actual state diverges from desired state and takes corrective actions in a loop. This means if you manually delete a pod that belongs to a Deployment, Kubernetes will create a replacement automatically - not because you asked it to, but because the controller noticed actual state (2 pods) diverged from desired state (3 pods). This also means Kubernetes is naturally idempotent: applying the same manifest twice is safe and has no unintended side effects." `
    "*Hint:* Observe Kubernetes reconciliation in action by manually deleting a pod from a 3-replica Deployment and timing how quickly the controller creates a replacement - then examine controller-manager logs to see the reconcile loop." `
    "*Hint:* Research the Kubernetes control plane components (API server, etcd, scheduler, controller-manager) and map each to its role in the observe-desired-state vs observe-actual-state reconciliation loop." `
    "*Hint:* Investigate the Kubernetes Operator pattern and how Custom Resource Definitions plus custom controllers extend the reconciliation model to application-specific lifecycle management (database provisioning, certificate renewal, etc.)."

# --- CTR-027: Docker vs VM ---
Patch-File "CTR-027" `
    "The VM vs container trade-off debate began seriously in 2013 when Docker popularised containers as an alternative to VM-per-service deployments. The initial framing (containers replace VMs) was quickly corrected by 2015: containers run INSIDE VMs in production. AWS Fargate (2017) and Firecracker microVMs (2018) blurred the boundary by providing VM-level isolation at near-container startup speed. gVisor (2018) and Kata Containers (2018) offered hybrid approaches." `
    "Different workload isolation requirements versus resource efficiency requirements cannot all be satisfied by a single abstraction - the choice between VMs and containers is inherently a trade-off driven by threat model and density requirements." `
    "The specific hypervisor implementations (KVM, Xen, VMware), container runtimes (runc, containerd), and the hybrid approaches (Firecracker, Kata) are implementation choices for satisfying the fundamental isolation-vs-efficiency trade-off." `
    "Match the isolation mechanism to the threat model, not to what is fashionable. VMs for inter-tenant isolation; containers within VMs for deployment efficiency. Combining both layers is not overhead - it is defence-in-depth applied to compute." `
    "- **Physical vs logical separation in networking** - VLANs (logical, like containers) vs separate physical switches (physical, like VMs); high-security environments require physical separation for the outer boundary`n- **Process isolation vs thread isolation** - threads share address space (like containers sharing a kernel); processes have separate address spaces (like VMs with separate kernels)`n- **Single-tenant vs multi-tenant databases** - shared database schema (like container isolation) vs separate database instances (like VM isolation) for regulatory data separation" `
    "AWS Lambda runs customer functions in Firecracker microVMs with 125ms boot times, not in Linux containers. Google Cloud Run also wraps containers in VM isolation (gVisor). Microsoft Azure Container Instances uses Hyper-V isolation. The largest container-as-a-service platforms in the world all use VM isolation for the outer boundary - they just made the VMs invisible to the user. The 'containers vs VMs' framing is a false dichotomy; the industry answer is always 'both'." `
    "*Hint:* Research Firecracker's architecture: it is a KVM-based microVM manager written in Rust with a minimal device model (no BIOS, no ACPI) - measure its boot time vs a standard QEMU/KVM VM and compare to a container start." `
    "*Hint:* Investigate gVisor's sandbox model: it runs a user-space kernel (Sentry) that intercepts container syscalls and applies them through a restricted set of host syscalls - how does this differ from namespace isolation in terms of syscall surface?" `
    "*Hint:* Compare the isolation guarantees of: (1) plain Linux container, (2) Kata Container (VM-wrapped container), (3) Firecracker microVM, and (4) full KVM VM - rank them by isolation strength and startup time."

# --- CTR-028: Ephemeral Container ---
Patch-File "CTR-028" `
    "Ephemeral containers were introduced as an alpha feature in Kubernetes 1.16 (2019) and graduated to stable in Kubernetes 1.25 (2022). They were created to address a specific problem: distroless and minimal images have no debug tools, making live debugging impossible without ephemeral containers. Previously, teams had to add debug tools to production images or build a debug variant, both with security implications." `
    "When a production container has no shell or debug tools (distroless image), diagnosing live issues requires attaching a temporary debug container to the running pod's namespaces - this capability is inherently necessary for production debuggability without bloating production images." `
    "The specific kubectl debug API, the ephemeral container PodSpec subresource, and the --target flag for sharing the PID namespace are Kubernetes implementation choices for providing this capability." `
    "Production artifacts should carry the minimum necessary to run; debug and diagnostic capabilities should be attachable on demand and removable without redeployment. Separate the runtime concern from the debugging concern." `
    "- **Production vs debug build of a binary** - compiled with and without -g debug symbols; the production binary is stripped; attaching gdb to a production process is conceptually similar to attaching an ephemeral debug container`n- **SSH break-glass access (PAM/BeyondTrust)** - production servers are locked; emergency access is granted temporarily via a privileged session with full audit; analogous to ephemeral container with elevated permissions`n- **Browser DevTools** - browser runs the production page; DevTools attach on demand without modifying the page; ephemeral containers attach to a running pod without modifying the pod spec" `
    "Ephemeral containers share the pod's network namespace by default, but they do NOT share the process namespace unless explicitly requested with --target=<container-name>. This means an ephemeral container attached to a distroless Java pod can see network activity (netstat, tcpdump) but cannot see the Java process's files or environment variables unless shareProcessNamespace is enabled at the pod level. Many engineers are surprised when their ephemeral ubuntu container cannot see the /app directory of the distroless container next to it - they are in the same network namespace but different mount namespaces." `
    "*Hint:* Use kubectl debug -it <pod> --image=ubuntu:22.04 --target=<container> to attach an ephemeral container to a running distroless pod - observe which namespaces are shared and which are not by default." `
    "*Hint:* Research the difference between kubectl debug (ephemeral container), kubectl exec (exec into existing container), and kubectl debug --copy-to (creates a debugging copy of the pod with modified spec) - when is each approach appropriate?" `
    "*Hint:* Investigate how ephemeral containers interact with Kubernetes RBAC - what permissions does a user need to create an ephemeral container? Why might you restrict this capability in a regulated production environment?"

# --- CTR-029: Init Container ---
Patch-File "CTR-029" `
    "Init containers were a Kubernetes alpha feature in 1.3 (2016), beta in 1.5 (2016), and stable in 1.6 (2017). They emerged from the pattern of needing a setup phase before the main application starts - database migration, secret fetching, config generation. Kubernetes 1.28 (2023) added sidecar init containers (restartPolicy: Always in initContainers) which run for the full pod lifecycle alongside main containers, not just during startup." `
    "Applications often need pre-conditions to be met before starting - database schema migrations, secrets to be present, configuration to be generated. The need for ordered startup dependencies is inherent in multi-component systems." `
    "The Kubernetes initContainers spec field, the sequential vs parallel execution model, and the success condition for init container completion are implementation choices; the startup ordering requirement is essential." `
    "Use dedicated setup phases to prepare the environment before starting the main process. The setup phase runs with a separate identity, image, and lifecycle from the main process - keeping concerns separated and auditable." `
    "- **Database migration as a CI/CD step** - run flyway migrate before deploying the new application version; init containers bring this pattern inside the Kubernetes pod lifecycle`n- **Service startup scripts (systemd ExecStartPre)** - systemd runs ExecStartPre commands before ExecStart; if any fail, the service does not start - identical semantics to init container failure`n- **Chef/Puppet pre-convergence checks** - verify system prerequisites (disk space, network connectivity) before applying configuration; fail fast if pre-conditions are not met" `
    "Init containers run to completion before the main container starts, which makes them a natural place for database migrations - but this creates a subtle problem at scale. If you have a Deployment with 10 replicas and you deploy a new version, Kubernetes may run 10 init containers simultaneously, each attempting to run the same database migration. Most migration tools (Flyway, Liquibase) use advisory locks to prevent concurrent migrations, but under high load these locks can time out, causing init containers to fail and preventing the deployment from succeeding. Production-grade migration strategies separate the migration job from the application deployment lifecycle." `
    "*Hint:* Create a pod with an init container that sleeps 30 seconds and observe with kubectl get pods -w how the pod transitions through Init:0/1, PodInitializing, and Running states - map this to the Kubernetes pod lifecycle documentation." `
    "*Hint:* Research Kubernetes sidecar init containers (initContainer with restartPolicy: Always, Kubernetes 1.28+) and how they enable observability agents and service mesh proxies to start before and outlive the main container lifecycle." `
    "*Hint:* Investigate the security difference between running a database migration as an init container (with production DB credentials in the pod) vs as a pre-deployment Kubernetes Job with a separate ServiceAccount and reduced permissions."

# --- CTR-030: Sidecar Container ---
Patch-File "CTR-030" `
    "The sidecar pattern was popularised by the service mesh movement (Linkerd 2016, Istio 2017), which injected a sidecar proxy (Envoy) into every pod to handle mTLS, telemetry, and traffic management. Kubernetes 1.28 (2023) formalised sidecar containers as first-class citizens with lifecycle guarantees via restartPolicy: Always in initContainers. Previously, sidecars had no lifecycle ordering guarantee - the main container could exit while the log-shipping sidecar was still draining." `
    "A pod needs multiple concerns addressed simultaneously (traffic proxying, log shipping, credential rotation) without coupling them into a single container image. The multi-concern separation need is inherent in production-grade applications." `
    "The specific Istio/Envoy proxy injection mechanism, the Kubernetes mutating webhook that injects sidecar containers, and the shared volume for log files between main and sidecar containers are implementation choices." `
    "Place each cross-cutting concern in a separately operated, independently deployable unit that runs alongside the main workload but does not modify it. The sidecar pattern is the Decorator design pattern applied to distributed systems." `
    "- **Decorator design pattern** - wraps an object with additional behaviour without modifying the original; an Istio sidecar wraps a pod's network traffic without modifying the application image`n- **Browser extensions** - add behaviour to a running web page without modifying the page source; the page and extension are independently deployed but share the same runtime context`n- **Unix pipes** - each command in a pipe is a sidecar to the previous; independently implemented tools chained together achieve composite behaviour" `
    "Kubernetes does not guarantee startup order between containers in a pod by default. A service mesh sidecar (like Istio's Envoy proxy) must be fully started before the main container's outbound traffic can be routed. Without the Kubernetes sidecar init container feature (1.28+), many Istio users experienced race conditions where the main container started before Envoy was ready, causing the first few outbound requests to fail. The workaround was a wait-for-envoy init container or sleep in the main container startup script - neither elegant. The formal sidecar lifecycle graduated to stable in Kubernetes 1.29." `
    "*Hint:* Deploy a pod with a log-tailing sidecar container sharing a volume with the main container (emptyDir) - observe with kubectl logs <pod> -c <sidecar> that the sidecar streams the main container's log file in real time." `
    "*Hint:* Research Istio's automatic sidecar injection mechanism (MutatingAdmissionWebhook) and how it adds the Envoy proxy container plus an init container (for iptables rules) to every pod in labelled namespaces." `
    "*Hint:* Investigate the security implications of sidecar containers sharing the pod's network namespace: a compromised sidecar can intercept all network traffic to/from the main container. How do service meshes address this trust boundary?"

# --- CTR-031: Container Resource Limits ---
Patch-File "CTR-031" `
    "Kubernetes resource requests and limits existed since Kubernetes 1.0 (2014) as a mechanism for the scheduler and cgroups. Quality of Service (QoS) classes (Guaranteed, Burstable, BestEffort) formalised in Kubernetes 1.5. Vertical Pod Autoscaler (VPA) for automatic limit tuning (alpha 2018, production-worthy 2022). Kubernetes 1.27 changed CPU throttling defaults (cgroups v2 support) reducing the CPU throttling latency problem that affected Java/JVM workloads." `
    "In a shared multi-tenant compute environment, processes must have bounded resource consumption - unlimited processes are a reliability risk to all neighbours. Enforcement is inherently necessary." `
    "The specific cgroups v1/v2 implementation, Kubernetes requests vs limits semantics, QoS class calculation, and VPA tuning are implementation choices; the resource bounding requirement is essential." `
    "Every shared resource needs a governing contract: a minimum guaranteed allocation (request) and a maximum allowable consumption (limit). These two numbers define the bound of acceptable behaviour and the scheduler's placement decisions." `
    "- **Rate limiting APIs** - each client gets a minimum throughput guarantee (request) and a maximum throughput cap (limit); exceeding the limit results in 429 throttling, not service degradation for all clients`n- **Database connection pools** - minimum pool size (always-available connections) and maximum pool size (hard cap); exceeding the cap blocks the caller rather than starving other users`n- **Cloud budget alerts and hard limits** - AWS budget alerts (soft limits) and service quotas (hard limits) mirror the request/limit semantic for cloud spend" `
    "CPU limits in Kubernetes cause CPU throttling even when the host has idle CPU capacity. A container with limits.cpu=500m uses cgroups to cap at 50% of one CPU core per 100ms period. If the container uses all 50ms of CPU in the first 10ms, it is throttled for the remaining 90ms of the period - even if the host is idle. This creates latency spikes in bursty workloads (web servers, JVM GC). Many performance-sensitive teams remove CPU limits entirely and rely on requests for scheduling, accepting the noisy-neighbour risk in exchange for eliminating throttle-induced latency. Setting no CPU limits is a deliberate trade-off, not an oversight." `
    "*Hint:* Deploy a Java application with CPU limit 500m and run a load test; use kubectl top pod and /sys/fs/cgroup/cpu/cpu.stat (nr_throttled) to observe CPU throttling - then increase or remove the limit and compare latency." `
    "*Hint:* Research Kubernetes QoS classes: what combination of requests/limits creates Guaranteed vs Burstable vs BestEffort, and which QoS class pods are evicted first under node memory pressure?" `
    "*Hint:* Investigate the Vertical Pod Autoscaler and how it observes historical resource usage to recommend requests/limits - compare its recommendations to manual sizing and understand when you should trust VPA vs set limits manually."

# --- CTR-032: Container Health Check ---
Patch-File "CTR-032" `
    "Docker HEALTHCHECK instruction was added in Docker 1.12 (2016). Kubernetes livenessProbe and readinessProbe existed since Kubernetes 1.0 (2014). Kubernetes 1.16 added startupProbe to handle slow-starting containers without liveness probe restarts. The common pattern of /health endpoints on HTTP services (Actuator in Spring Boot, Liveness/Readiness in Quarkus) became standard practice by 2018." `
    "In a self-healing distributed system, the orchestrator must have a reliable signal of whether a container is running correctly and ready to serve traffic - this health visibility is inherently necessary for automated recovery." `
    "The specific Kubernetes livenessProbe/readinessProbe/startupProbe fields, the HTTP vs exec vs gRPC probe types, and the failure/success thresholds are implementation choices; the health signalling requirement is essential." `
    "A process must self-report its health state to its environment. External polling is insufficient for fast failure detection at scale. Build health endpoints that reflect the process's ability to serve correctly, not just its ability to accept TCP connections." `
    "- **Circuit breaker pattern** - a service monitors its success rate and transitions between CLOSED, OPEN, HALF-OPEN states; Kubernetes readiness probe is a simpler external view of the same principle`n- **Load balancer health checks** - AWS ALB, Nginx, and HAProxy all implement probe-based backend health checks before routing traffic; Kubernetes readiness probe is the in-cluster equivalent`n- **AWS ELB Target Group health checks** - HTTP GET every 30s with timeout 5s, 2 consecutive failures = unhealthy - identical semantics to Kubernetes readinessProbe" `
    "Liveness and readiness probes are independent signals with different semantics that are frequently confused. A FAILING liveness probe causes the container to be RESTARTED. A FAILING readiness probe causes the pod to be REMOVED from the load balancer while it continues running. Configuring liveness with too low a timeout on a Java service that has occasional GC pauses causes the container to restart during normal GC activity - creating a restart loop that looks like a bug but is actually an overly aggressive health check. Using a startup probe for slow-starting containers and separate liveness/readiness probes for steady-state health is the recommended production pattern." `
    "*Hint:* Configure a Spring Boot application with a liveness probe timeout of 1 second and trigger a GC pause (using JVM stress flags); observe the pod restart pattern and understand why startupProbe is needed for JVM workloads." `
    "*Hint:* Research the Kubernetes readinessGates feature and how it extends the readiness signal to include external conditions (load balancer registered, DNS propagated) beyond what the container's own health endpoint can report." `
    "*Hint:* Investigate the difference between readiness and liveness probes at the network load balancer level: how does kube-proxy use readiness probe status to update iptables rules and endpoint slices in real time?"

# --- CTR-033: Image Tag Strategy ---
Patch-File "CTR-033" `
    "The image tag problem emerged as a production reliability issue around 2015 when teams pinned to latest and experienced unexpected breakage. Digest pinning (registry.local/nginx@sha256:abc) became standard practice by 2018. Semantic versioning for container images (following SemVer) was the first improvement. Immutable tags enforced by registry policies (ECR immutable tags, GCR tag policies) became common practice from 2020. Renovate Bot and Dependabot for automated image version bumps emerged as the GitOps solution by 2021." `
    "Distributing a specific, reproducible version of software requires a stable, immutable reference. Mutable references (tags) are a convenience for humans; production systems need the guarantee of content-addressed references (digests)." `
    "The specific tag naming conventions (semver, git SHA, date-based, environment-based), registry-enforced immutability features, and automated bump tools are implementation choices; the immutability requirement is essential." `
    "Use mutable tags (semver, latest) as human-readable shortcuts and immutable digests as the ground truth for production deployments. Never rely on a mutable reference for production repeatability." `
    "- **Git tags vs git commits** - git tags are mutable human-readable shortcuts; commit SHAs are the immutable references; production deployments should pin to commit SHA, not branch name`n- **npm --save-exact vs version ranges** - ^1.2.3 is a mutable reference (may resolve to 1.3.0 next week); 1.2.3 exact is still mutable (can be yanked); package-lock.json SHA is the immutable reference`n- **DNS vs IP addresses** - DNS names are mutable (can be updated); IP addresses at a point in time are more stable but still can change; content digests (like Consul service health) are the stable reference" `
    "The latest tag is not just mutable - it is actively harmful in CI/CD. When you specify image: myapp:latest in a Kubernetes Deployment, Kubernetes caches the locally pulled latest image. If you push a new latest image and do not restart the pod, the pod continues running the OLD latest. When the pod eventually restarts (crash, node drain, scale), it pulls the NEW latest - but all pods were not restarted simultaneously, so different replicas may be running different code under the same tag. This is how latest tags cause phantom split-brain deployments where different pod instances serve different application versions." `
    "*Hint:* Create a Kubernetes Deployment with imagePullPolicy: Always and image: myapp:latest; push a new latest image; observe that kubectl rollout restart is required to apply the new image despite the tag name being unchanged." `
    "*Hint:* Research ECR image tag immutability enforcement and how it prevents overwriting an existing tag - compare the operational workflow with and without immutable tags for a continuous deployment pipeline." `
    "*Hint:* Investigate Renovate Bot configuration for automated Docker image version bumps in Kubernetes manifests and Dockerfiles - understand how it discovers new versions, creates PRs, and runs automated tests before merging."

# --- CTR-034: Docker BuildKit ---
Patch-File "CTR-034" `
    "BuildKit was developed by Docker and open-sourced in 2017. It became the default docker build backend in Docker 23.0 (2023). Key BuildKit features: parallel stage builds, secret mounts (RUN --mount=type=secret), SSH agent mounts, remote cache backends (--cache-from registry), heredoc syntax (Docker 23+), and the OCI image format output. BuildKit uses a DAG (directed acyclic graph) of build steps rather than the sequential processing of the legacy builder." `
    "Container image builds need efficient caching, parallel execution, and secret handling that does not bake credentials into image layers - these are inherent requirements for production-scale build pipelines." `
    "The specific BuildKit LLB (Low-Level Build) intermediate representation, the Buildx client plugin architecture, and the cache manifest format are implementation choices; the need for efficient, secure builds is essential." `
    "Represent builds as a DAG (directed acyclic graph) of operations rather than a sequential list of steps. Identify which steps are independent and execute them in parallel. Cache at the operation level (not the step level) for maximum cache hits." `
    "- **Gradle build graph** - Gradle models a build as a DAG of tasks; independent tasks run in parallel; incremental builds skip up-to-date tasks - same model as BuildKit's LLB graph`n- **Make with parallel jobs (make -j8)** - Make's dependency graph enables parallel job execution; -j8 runs 8 parallel recipes; BuildKit's parallel stage execution is the container build equivalent`n- **CI/CD pipeline parallelism** - GitHub Actions jobs with no dependency run in parallel; jobs with needs: [build] run after the upstream job - same DAG semantics" `
    "BuildKit's secret mounts (RUN --mount=type=secret,id=npmrc,target=/root/.npmrc) allow a build to use a secret during a RUN instruction without the secret ever being committed to any image layer. The secret is a temporary file injected from the host into the build step's filesystem, used during execution, and then removed before the layer snapshot is taken. This is cryptographically impossible to achieve with the legacy docker build - ENV-based secrets appear in docker history permanently. Even docker history --no-trunc shows the ENV value. BuildKit secrets were specifically designed to solve this supply chain security problem." `
    "*Hint:* Build an image with DOCKER_BUILDKIT=1 docker build and then without (classic builder); compare the output verbosity, build graph visualisation (--progress=plain), and the handling of parallel stages." `
    "*Hint:* Research BuildKit's remote cache backend (--cache-to type=registry,ref=myregistry/cache --cache-from type=registry,ref=myregistry/cache) and simulate a cold CI runner environment to measure cache hit rate improvement." `
    "*Hint:* Investigate BuildKit's RUN --mount=type=cache,target=/var/cache/apt and how it persists the apt cache between builds without polluting the image layers - measure the build time improvement for apt-heavy Dockerfiles."

# --- CTR-035: Podman ---
Patch-File "CTR-035" `
    "Podman was developed by Red Hat starting in 2018 as a daemonless alternative to Docker. It uses the same OCI image format and runtime (runc) as Docker, providing CLI compatibility. Podman 2.0 (2020) added REST API compatibility with Docker's API, enabling drop-in replacement. Podman 3.0 (2021) added docker-compose compatibility. Podman Desktop (2022) provides a GUI for macOS/Windows similar to Docker Desktop. Red Hat RHEL 8+ ships Podman as the default container engine, with Docker available but not installed by default." `
    "A container engine that is usable by non-root users without a privileged daemon is inherently necessary for environments where running a root-privileged daemon is a security policy violation (enterprise Linux servers, shared HPC environments)." `
    "The specific fork-exec model (vs Docker's daemon model), the Podman REST API, and the podman-compose tool are implementation choices; the need for a rootless, daemonless container engine is essential." `
    "Eliminate privileged background processes where possible. Run operations in the context of the requesting user's permissions. A zero-persistent-process architecture is more secure and auditable than a persistent privileged daemon." `
    "- **Serverless vs traditional server** - serverless functions run in the context of the invocation (no persistent process); traditional servers run a persistent daemon; Podman's fork-exec model mirrors serverless over daemons`n- **SSH vs always-on VPN** - SSH connects on demand per-command, authenticates, executes, and disconnects; always-on VPN is a persistent privileged connection; Podman operates like SSH`n- **sudo vs setuid binaries** - sudo runs a command with elevated privileges for one invocation; a setuid daemon is always elevated; Podman with user namespaces is the sudo model for containers" `
    "Podman's biggest hidden advantage over Docker in enterprise Linux environments is SELinux integration. Red Hat/Fedora/RHEL systems run SELinux in enforcing mode by default. Docker's daemon architecture frequently conflicts with SELinux policy because the daemon runs as root and must be granted broad SELinux permissions. Podman's fork-exec model runs each container in the user's SELinux context, meaning SELinux policies apply naturally without special exemptions. On RHEL systems, teams that struggle with Docker SELinux denials consistently find Podman just works - which is why RHEL 8 ships Podman by default." `
    "*Hint:* Run the same docker build and podman build commands on the same Dockerfile and inspect the running process tree with ps aux during the build - observe that Podman spawns a fork of the CLI while Docker delegates to the background daemon." `
    "*Hint:* Research Podman's user namespace remapping for rootless containers: run podman run --userns=auto alpine id and then check /proc/self/uid_map on the host to see the UID mapping without root involvement." `
    "*Hint:* Investigate Podman pods (podman pod create) and how they model the Kubernetes pod concept locally - run multiple containers sharing a network namespace and compare to docker network create equivalents."

